type multipartRequestBody struct {
	Fields     map[string]string
	FileFields map[string]string
}

func encodeMultipartBody(body multipartRequestBody) ([]byte, string, error) {
	var buf bytes.Buffer
	writer := multipart.NewWriter(&buf)
	for fieldName, value := range body.Fields {
		if err := writer.WriteField(fieldName, value); err != nil {
			_ = writer.Close()
			return nil, "", fmt.Errorf("writing multipart field %q: %w", fieldName, err)
		}
	}
	for fieldName, filePath := range body.FileFields {
		file, err := os.Open(filePath)
		if err != nil {
			_ = writer.Close()
			return nil, "", fmt.Errorf("opening multipart file field %q (%q): %w", fieldName, filePath, err)
		}
		part, err := writer.CreateFormFile(fieldName, filepath.Base(filePath))
		if err != nil {
			_ = file.Close()
			_ = writer.Close()
			return nil, "", fmt.Errorf("creating multipart file field %q (%q): %w", fieldName, filePath, err)
		}
		if _, err := io.Copy(part, file); err != nil {
			_ = file.Close()
			_ = writer.Close()
			return nil, "", fmt.Errorf("copying multipart file field %q (%q): %w", fieldName, filePath, err)
		}
		if err := file.Close(); err != nil {
			_ = writer.Close()
			return nil, "", fmt.Errorf("closing multipart file field %q (%q): %w", fieldName, filePath, err)
		}
	}
	if err := writer.Close(); err != nil {
		return nil, "", fmt.Errorf("finalizing multipart body: %w", err)
	}
	return buf.Bytes(), writer.FormDataContentType(), nil
}

type formRequestBody struct {
	Fields url.Values
}

func encodeFormBody(body formRequestBody) ([]byte, string, error) {
	return []byte(body.Fields.Encode()), "application/x-www-form-urlencoded", nil
}

// do executes an HTTP request. headerOverrides, when non-nil, override global
// RequiredHeaders for this specific request (used for per-endpoint API versioning).
func (c *Client) do(method, path string, params map[string]string, body any, headerOverrides map[string]string) (json.RawMessage, int, error) {
	protectedAuthConfig := IsAuthConfigPath(path)
	if protectedAuthConfig && (method == http.MethodGet || method == http.MethodPatch) {
		// Pre-fix releases cached the raw AuthConfigResponse in owner-readable or
		// world-readable files. Remove the entire opaque-key cache before every
		// protected operation because individual legacy entries cannot be mapped
		// back to their route safely.
		if err := c.invalidateCache(); err != nil {
			return nil, 0, fmt.Errorf("purging legacy auth-config cache: %w", err)
		}
	}
	targetURL := c.BaseURL + path

	var bodyBytes []byte
	var contentType string
	if body != nil {
		if multipartBody, ok := body.(multipartRequestBody); ok {
			b, ct, err := encodeMultipartBody(multipartBody)
			if err != nil {
				return nil, 0, err
			}
			bodyBytes = b
			contentType = ct
		} else if formBody, ok := body.(formRequestBody); ok {
			b, ct, err := encodeFormBody(formBody)
			if err != nil {
				return nil, 0, err
			}
			bodyBytes = b
			contentType = ct
		} else {
			b, err := json.Marshal(body)
			if err != nil {
				return nil, 0, fmt.Errorf("marshaling body: %w", err)
			}
			bodyBytes = b
			contentType = "application/json"
		}
	}
	if protectedAuthConfig && method == http.MethodPatch {
		if err := ValidateAuthConfigRequest(bodyBytes); err != nil {
			return nil, 0, fmt.Errorf("validating auth config request: %w", err)
		}
	}

	// Resolve auth material before the dry-run branch so --dry-run can preview
	// exactly what would be sent. Uses only cached credentials; a token that
	// requires a network refresh will be re-fetched on the live request path,
	// not during dry-run.
	authHeader, err := c.authHeader()
	if err != nil {
		return nil, 0, err
	}

	// Build the request for dry-run display or actual execution
	if c.DryRun {
		return c.dryRun(method, targetURL, path, params, bodyBytes, headerOverrides, authHeader)
	}

	const maxRetries = 3
	var lastErr error

	for attempt := 0; attempt <= maxRetries; attempt++ {
		// Proactive rate limiting — wait before sending
		c.limiter.Wait()
		var bodyReader io.Reader
		if bodyBytes != nil {
			bodyReader = strings.NewReader(string(bodyBytes))
		}

		req, err := http.NewRequest(method, targetURL, bodyReader)
		if err != nil {
			return nil, 0, fmt.Errorf("creating request: %w", err)
		}
		if bodyBytes != nil {
			req.Header.Set("Content-Type", contentType)
		}

		if params != nil {
			q := req.URL.Query()
			for k, v := range params {
				if v != "" {
					q.Set(k, v)
				}
			}
			req.URL.RawQuery = q.Encode()
		}

		if authHeader != "" {
			req.Header.Set("Authorization", authHeader)
		}
		if c.Config != nil {
			for k, v := range c.Config.Headers {
				req.Header.Set(k, v)
			}
		}
		// Per-endpoint header overrides (e.g., different API version per resource)
		for k, v := range headerOverrides {
			req.Header.Set(k, v)
		}
		if req.Header.Get("User-Agent") == "" {
			req.Header.Set("User-Agent", "supabase-pp-cli/1.0.0")
		}
		// Go's net/http omits Accept by default; browsers, curl, and other
		// stdlibs always send it. Fingerprint-checking WAFs (Imperva, Akamai,
		// Cloudflare bot-mode, DataDome) flag the absence as a bot signal
		// and answer with empty-body 5xx, 403, or a challenge redirect
		// depending on vendor and rule tier. The value is application/json
		// rather than */* because strict-JSON APIs (Zendesk, Atlassian REST,
		// Salesforce) return 415 on anything that isn't literally
		// application/json; specs that need a different content type
		// (vendor mediatypes, XML, HTML) declare it via RequiredHeaders or
		// per-endpoint headerOverrides, both of which run before this
		// if-empty default.
		if req.Header.Get("Accept") == "" {
			req.Header.Set("Accept", "application/json")
		}

		// Install the boundary on a request-local client clone so concurrent
		// calls cannot race on redirect policy. Protected auth-config requests
		// never follow redirects: even a response that is later sanitized must
		// not forward its Authorization header to another route or host. Other
		// requests preserve the caller policy except that they cannot redirect
		// into the protected endpoint after being classified as cacheable.
		requestClient := *c.HTTPClient
		callerCheckRedirect := requestClient.CheckRedirect
		requestClient.CheckRedirect = func(redirected *http.Request, via []*http.Request) error {
			if protectedAuthConfig || IsAuthConfigPath(redirected.URL.String()) {
				return errAuthConfigRedirectBoundary
			}
			if callerCheckRedirect != nil {
				return callerCheckRedirect(redirected, via)
			}
			if len(via) >= 10 {
				return fmt.Errorf("stopped after 10 redirects")
			}
			return nil
		}

		resp, err := requestClient.Do(req)
		if err != nil {
			if errors.Is(err, errAuthConfigRedirectBoundary) {
				if resp != nil && resp.Body != nil {
					_ = resp.Body.Close()
				}
				// net/http wraps CheckRedirect errors in *url.Error, whose string
				// contains the full rejected destination URL. Never wrap that value:
				// a protected Location can itself carry a credential-bearing query.
				return nil, 0, errors.New("redirect into protected auth-config endpoint refused")
			}
			lastErr = fmt.Errorf("%s %s: %w", method, path, err)
			continue
		}

		respBody, err := io.ReadAll(resp.Body)
		resp.Body.Close()
		if err != nil {
			return nil, 0, fmt.Errorf("reading response: %w", err)
		}
		respBody = sanitizeJSONResponse(respBody)

		// Success
		if resp.StatusCode < 400 {
			c.limiter.OnSuccess()
			result := json.RawMessage(respBody)
			if protectedAuthConfig {
				result, err = SanitizeAuthConfigResponse(result)
				if err != nil {
					return nil, 0, fmt.Errorf("sanitizing auth config response: %w", err)
				}
			}
			if method != http.MethodGet && !c.DryRun {
				_ = c.invalidateCache()
			}
			return result, resp.StatusCode, nil
		}
		errorBody := truncateBody(respBody)
		if protectedAuthConfig {
			errorBody = "response body redacted"
		}

		apiErr := &APIError{
			Method:     method,
			Path:       path,
			StatusCode: resp.StatusCode,
			Body:       errorBody,
		}

		// Rate limited - adjust adaptive limiter and retry
		if resp.StatusCode == 429 && attempt < maxRetries {
			c.limiter.OnRateLimit()
			wait := cliutil.RetryAfter(resp)
			fmt.Fprintf(os.Stderr, "rate limited, waiting %s (attempt %d/%d, rate adjusted to %.1f req/s)\n", wait, attempt+1, maxRetries, c.limiter.Rate())
			time.Sleep(wait)
			lastErr = apiErr
			continue
		}

		// Server error - retry with backoff
		if resp.StatusCode >= 500 && attempt < maxRetries {
			wait := time.Duration(math.Pow(2, float64(attempt))) * time.Second
			fmt.Fprintf(os.Stderr, "server error %d, retrying in %s (attempt %d/%d)\n", resp.StatusCode, wait, attempt+1, maxRetries)
			time.Sleep(wait)
			lastErr = apiErr
			continue
		}

		// Client error or retries exhausted - return the error
		return nil, resp.StatusCode, apiErr
	}

	return nil, 0, lastErr
}

// dryRun prints the outgoing request exactly as the live path would send it,
// using the auth material already resolved in `do()`. Never triggers a network
// call — the caller is responsible for passing cached auth material only.
func (c *Client) dryRun(method, targetURL, path string, params map[string]string, body []byte, headerOverrides map[string]string, authHeader string) (json.RawMessage, int, error) {
	fmt.Fprintf(os.Stderr, "%s %s\n", method, targetURL)
	queryPrinted := false
	if params != nil {
		keys := make([]string, 0, len(params))
		for k := range params {
			if params[k] != "" {
				keys = append(keys, k)
			}
		}
		sort.Strings(keys)
		for _, k := range keys {
			sep := "?"
			if queryPrinted {
				sep = "&"
			}
			fmt.Fprintf(os.Stderr, "  %s%s=%s\n", sep, k, params[k])
			queryPrinted = true
		}
	}
	_ = queryPrinted
	if body != nil {
		if IsAuthConfigPath(path) {
			var err error
			body, err = sanitizeAuthConfigRequestPreview(body)
			if err != nil {
				return nil, 0, fmt.Errorf("sanitizing auth config dry-run body: %w", err)
			}
		}
		var pretty json.RawMessage
		if json.Unmarshal(body, &pretty) == nil {
			enc := json.NewEncoder(os.Stderr)
			enc.SetIndent("  ", "  ")
			fmt.Fprintf(os.Stderr, "  Body:\n")
			enc.Encode(pretty)
		}
	}
	if authHeader != "" {
		if IsAuthConfigPath(path) {
			fmt.Fprintln(os.Stderr, "  Authorization: [REDACTED]")
		} else {
			fmt.Fprintf(os.Stderr, "  %s: %s\n", "Authorization", maskToken(authHeader))
		}
	}
	fmt.Fprintf(os.Stderr, "\n(dry run - no request sent)\n")
	return json.RawMessage(`{"dry_run": true}`), 0, nil
}

func (c *Client) ConfiguredTimeout() time.Duration {
	if c.HTTPClient != nil && c.HTTPClient.Timeout > 0 {
		return c.HTTPClient.Timeout
	}
	return 30 * time.Second
}

func (c *Client) authHeader() (string, error) {
	if c.Config == nil {
		return "", nil
	}
	return c.Config.AuthHeader(), nil
}

// sanitizeJSONResponse strips known JSONP/XSSI prefixes and UTF-8 BOM from
// response bodies so that downstream JSON parsing succeeds. For clean JSON
// responses these checks are no-ops.
func sanitizeJSONResponse(body []byte) []byte {
	// UTF-8 BOM
	body = bytes.TrimPrefix(body, []byte("\xEF\xBB\xBF"))

	// JSONP/XSSI prefixes, ordered longest-first where prefixes overlap
	prefixes := [][]byte{
		[]byte(")]}'\n"),
		[]byte(")]}'"),
		[]byte("{}&&"),
		[]byte("for(;;);"),
		[]byte("while(1);"),
	}
	for _, p := range prefixes {
		if bytes.HasPrefix(body, p) {
			body = bytes.TrimPrefix(body, p)
			body = bytes.TrimLeft(body, " \t\r\n")
			break
		}
	}
	return body
}

// maskToken redacts all but the last 4 characters of a token for safe display.
func maskToken(token string) string {
	if token == "" {
		return ""
	}
	if len(token) <= 4 {
		return "****"
	}
	return "****" + token[len(token)-4:]
}

func truncateBody(b []byte) string {
	s := string(b)
	if len(s) > 200 {
		return s[:200] + "..."
	}
	return s
}
